/// <summary>
///    The <c>ETGSalesRegisterReportUIBuilder</c> class is the user interface builder class for the associated SQL
///    Server Reporting Services (SSRS) report.
/// </summary>
public class ETGSalesRegisterReportUIBuilder extends SrsReportDataContractUIBuilder
{
    ETGSalesRegisterReportContract  contract;

}

Method.Source:
/// <summary>
///    building all parameters
/// </summary>
public void build()
{
    contract = this.dataContractObject();

    this.addDialogField(methodStr(ETGSalesRegisterReportContract, parmFromDate), contract);
    this.addDialogField(methodStr(ETGSalesRegisterReportContract, parmToDate), contract);
    this.addDialogField(methodStr(ETGSalesRegisterReportContract, parmFinancialDimSet), contract);
    this.addDialogField(methodStr(ETGSalesRegisterReportContract, parmIsDetailReport), contract);
    this.addDialogField(methodStr(ETGSalesRegisterReportContract, parmViewConfigId), contract);
    this.addDialogField(methodStr(ETGSalesRegisterReportContract, parmViewInventSizeId), contract);
    this.addDialogField(methodStr(ETGSalesRegisterReportContract, parmViewInventColorId), contract);
    this.addDialogField(methodStr(ETGSalesRegisterReportContract, parmViewInventStyleId), contract);
    this.addDialogField(methodStr(ETGSalesRegisterReportContract, parmViewInventSiteId), contract);
    this.addDialogField(methodStr(ETGSalesRegisterReportContract, parmViewInventLocationId), contract);
    this.addDialogField(methodStr(ETGSalesRegisterReportContract, parmViewWMSLocationId), contract);
    this.addDialogField(methodStr(ETGSalesRegisterReportContract, parmViewLicensePlateId), contract);
    this.addDialogField(methodStr(ETGSalesRegisterReportContract, parmViewInventStatus), contract);
    this.addDialogField(methodStr(ETGSalesRegisterReportContract, parmViewInventBatchId), contract);
    this.addDialogField(methodStr(ETGSalesRegisterReportContract, parmViewInventSerialId), contract);
    this.addDialogField(methodStr(ETGSalesRegisterReportContract, parmViewInventOwnerId_RU), contract);
}

/// <summary>
///    creating dialog fields
/// </summary>
public void postBuild()
{
    DialogField     finDimSet;

    super();

    finDimSet = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETGSalesRegisterReportContract, parmFinancialDimSet));
    finDimSet.registerOverrideMethod(methodStr(FormStringControl, lookup), methodStr(ETGSalesRegisterReportUIBuilder, finDimSetLookup), this);
}

/// <summary>
///    creating dimension sets lookup
/// </summary>
/// <param name = "_formStringControl">form string control</param>
public void finDimSetLookup(FormStringControl   _formStringControl)
{
    Query                   query = new Query();
    QueryBuildDataSource    qbds;
    SysTableLookup          sysTableLookup = SysTableLookup::newParameters(tablenum(DimensionHierarchy), _formStringControl);

    sysTableLookup.addLookupfield(fieldNum(DimensionHierarchy, Name));
    sysTableLookup.addLookupfield(fieldNum(DimensionHierarchy, Description));

    qbds = query.addDataSource(tableNum(DimensionHierarchy));
    qbds.addRange(fieldNum(DimensionHierarchy, StructureType)).value(queryValue(DimensionHierarchyType::Focus));
    qbds.addRange(fieldNum(DimensionHierarchy, IsSystemGenerated)).value(queryValue(NoYes::No));

    sysTableLookup.parmQuery(query);
    sysTableLookup.performFormLookup();
}
